<?phpnamespace App\Entity;use App\Repository\BienClientRepository;use DateTimeInterface;use Doctrine\Common\Collections\ArrayCollection;use Doctrine\Common\Collections\Collection;use Doctrine\ORM\Mapping as ORM;use Vich\UploaderBundle\Mapping\Annotation as Vich;/** * @ORM\Entity(repositoryClass=BienClientRepository::class) * @Vich\Uploadable() */class BienClient{    /**     * @ORM\Id     * @ORM\GeneratedValue     * @ORM\Column(type="integer")     */    private $id;    /**     * @ORM\Column(type="string", length=100)     */    private $numeroDocument;    /**     * @ORM\Column(type="datetime")     */    private $createdAt;    /**     * @ORM\Column(type="datetime", nullable=true)     */    private $updatedAt;    /**     * @ORM\ManyToOne(targetEntity=Quartier::class, inversedBy="bienClients")     */    private $Quartier;    /**     * @ORM\ManyToOne(targetEntity=KohUtilisateur::class, inversedBy="bienClients")     */    private $kohUtilisateur;    /**     * @ORM\OneToMany(targetEntity=Expertise::class, mappedBy="bienClient", cascade={"persist","remove"})     */    private $expertises;    /**     * @var Expertise     */    private $lastExpertise;    /**     * @ORM\Column(type="boolean")     */    private $isForStructure;    /**     * @ORM\Column(type="string", length=255, nullable=true)     */    private $ninacad;    public function __construct()    {        $this->expertises = new ArrayCollection();    }    public function getId(): ?int    {        return $this->id;    }    public function getNumeroDocument(): ?string    {        return $this->numeroDocument;    }    public function setNumeroDocument(string $numeroDocument): self    {        $this->numeroDocument = $numeroDocument;        return $this;    }    public function getCreatedAt(): ?DateTimeInterface    {        return $this->createdAt;    }    public function setCreatedAt(DateTimeInterface $createdAt): self    {        $this->createdAt = $createdAt;        return $this;    }    public function getUpdatedAt(): ?DateTimeInterface    {        return $this->updatedAt;    }    public function setUpdatedAt(?DateTimeInterface $updatedAt): self    {        $this->updatedAt = $updatedAt;        return $this;    }    public function getQuartier(): ?Quartier    {        return $this->Quartier;    }    public function setQuartier(?Quartier $Quartier): self    {        $this->Quartier = $Quartier;        return $this;    }    public function getKohUtilisateur(): ?KohUtilisateur    {        return $this->kohUtilisateur;    }    public function setKohUtilisateur(?KohUtilisateur $kohUtilisateur): self    {        $this->kohUtilisateur = $kohUtilisateur;        return $this;    }    /**     * @return Collection|Expertise[]     */    public function getExpertises(): Collection    {        return $this->expertises;    }    public function addExpertise(Expertise $expertise): self    {        if (!$this->expertises->contains($expertise)) {            $this->expertises[] = $expertise;            $expertise->setBienClient($this);        }        return $this;    }    public function removeExpertise(Expertise $expertise): self    {        if ($this->expertises->contains($expertise)) {            $this->expertises->removeElement($expertise);            // set the owning side to null (unless already changed)            if ($expertise->getBienClient() === $this) {                $expertise->setBienClient(null);            }        }        return $this;    }    /**     * @return Expertise     */    public function getLastExpertise(): Expertise    {        return $this->lastExpertise;    }    /**     * @param Expertise $lastExpertise     */    public function setLastExpertise(Expertise $lastExpertise): void    {        $this->lastExpertise = $lastExpertise;    }    public function getIsForStructure(): ?bool    {        return $this->isForStructure;    }    public function setIsForStructure(bool $isForStructure): self    {        $this->isForStructure = $isForStructure;        return $this;    }    public function getNinacad(): ?string    {        return $this->ninacad;    }    public function setNinacad(?string $ninacad): self    {        $this->ninacad = $ninacad;        return $this;    }}